const POLAROID_GRADIENTS = [
  ["#FF9EA8", "#FFC157"],
  ["#073B4C", "#FF9EA8"],
  ["#2FBFAE", "#FFC157"],
];

function drawRoundedRect(ctx, x, y, w, h, r) {
  ctx.beginPath();
  ctx.moveTo(x + r, y);
  ctx.arcTo(x + w, y, x + w, y + h, r);
  ctx.arcTo(x + w, y + h, x, y + h, r);
  ctx.arcTo(x, y + h, x, y, r);
  ctx.arcTo(x, y, x + w, y, r);
  ctx.closePath();
}

function wrapCanvasText(ctx, text, x, y, maxWidth, lineHeight) {
  const words = text.split(" ");
  let line = "";
  let lines = [];
  for (const word of words) {
    const test = line ? `${line} ${word}` : word;
    if (ctx.measureText(test).width > maxWidth && line) {
      lines.push(line);
      line = word;
    } else {
      line = test;
    }
  }
  if (line) lines.push(line);
  const startY = y - ((lines.length - 1) * lineHeight) / 2;
  lines.forEach((l, i) => ctx.fillText(l, x, startY + i * lineHeight));
}

function downloadPolaroid(photo, index) {
  const scale = 3;
  const width = 340 * scale;
  const height = 410 * scale;
  const pad = 20 * scale;
  const photoSize = width - pad * 2;

  const canvas = document.createElement("canvas");
  canvas.width = width;
  canvas.height = height;
  const ctx = canvas.getContext("2d");

  const finish = () => {
    ctx.fillStyle = "#1C1B2E";
    ctx.font = `${13 * scale}px "Courier New", monospace`;
    ctx.textAlign = "center";
    wrapCanvasText(
      ctx,
      photo.caption,
      width / 2,
      pad + photoSize + 34 * scale,
      photoSize,
      18 * scale
    );

    canvas.toBlob((blob) => {
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = `hemyly-e-eu-${index + 1}.png`;
      document.body.appendChild(a);
      a.click();
      a.remove();
      URL.revokeObjectURL(url);
    }, "image/png");
  };

  ctx.fillStyle = "#FBEFDD";
  drawRoundedRect(ctx, 0, 0, width, height, 10 * scale);
  ctx.fill();

  if (photo.image) {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      ctx.save();
      drawRoundedRect(ctx, pad, pad, photoSize, photoSize, 4 * scale);
      ctx.clip();
      const ratio = Math.max(photoSize / img.width, photoSize / img.height);
      const drawW = img.width * ratio;
      const drawH = img.height * ratio;
      const dx = pad + (photoSize - drawW) / 2;
      const dy = pad + (photoSize - drawH) / 2;
      ctx.drawImage(img, dx, dy, drawW, drawH);
      ctx.restore();
      finish();
    };
    img.src = photo.image;
    return;
  }

  const [c1, c2] = POLAROID_GRADIENTS[index % POLAROID_GRADIENTS.length];
  const grad = ctx.createLinearGradient(pad, pad, pad + photoSize, pad + photoSize);
  grad.addColorStop(0, c1);
  grad.addColorStop(1, c2);
  ctx.fillStyle = grad;
  drawRoundedRect(ctx, pad, pad, photoSize, photoSize, 4 * scale);
  ctx.fill();

  ctx.font = `${100 * scale}px sans-serif`;
  ctx.textAlign = "center";
  ctx.textBaseline = "middle";
  ctx.fillText(photo.emoji, width / 2, pad + photoSize / 2);

  finish();
}

function PolaroidLightbox({ photo, index, onClose }) {
  return (
    <div className="lightbox-overlay" onClick={onClose}>
      <div className="lightbox-polaroid" onClick={(e) => e.stopPropagation()}>
        <button className="lightbox-close" onClick={onClose} aria-label="Fechar">
          <X size={16} />
        </button>
        <div className={`lightbox-photo lightbox-photo-${index}`}>
          {photo.image ? (
            <img src={photo.image} alt={photo.caption} />
          ) : (
            <span>{photo.emoji}</span>
          )}
        </div>
        <p className="lightbox-caption">{photo.caption}</p>
        <button
          className="lightbox-download"
          onClick={() => downloadPolaroid(photo, index)}
        >
          <Download size={16} />
          <span>salvar recordação</span>
        </button>
      </div>
    </div>
  );
}

